export const ArtisticMarker = ({
  type,
  size = 64,
  isSelected,
  isLightMode,
  markerSvg,
  imageUrl,
  title,
}: ArtisticMarkerProps) => {
  const [dynamicSvg, setDynamicSvg] = React.useState<string | null>(null);

  React.useEffect(() => {
    setDynamicSvg(null);
    if (type !== 'fauna' && type !== 'universidad') return;

    let filename = '';
    if (type === 'fauna') {
      const getSanitizedName = (text: string) => {
        return text
          .toLowerCase()
          .normalize('NFD')
          .replace(/[\u0300-\u036f]/g, '')
          .replace(/[^a-z0-9]/g, '_')
          .replace(/_+/g, '_')
          .replace(/(^_|_$)/g, '');
      };
      const name = getSanitizedName(title || 'lobo_marino');
      const suffix = !isLightMode ? '_blanca' : '';
      filename = `${name}${suffix}.svg`;
    } else if (type === 'universidad') {
      const lowerTitle = (title || '').toLowerCase();
      if (
        lowerTitle.includes('sebastián') ||
        lowerTitle.includes('sebastian') ||
        lowerTitle.includes('uss')
      ) {
        filename = 'logo_uss.svg';
      } else if (
        lowerTitle.includes('tomas') ||
        lowerTitle.includes('tomás') ||
        lowerTitle.includes('ust')
      ) {
        filename = 'logo_santo_tomas.svg';
      } else if (lowerTitle.includes('inacap')) {
        filename = 'logo_inacap.svg';
      }
    }

    if (!filename) return;

    const apiBaseUrl = process.env.EXPO_PUBLIC_BACKEND_URL || 'http://localhost:8080';
    const primaryUrl = `${apiBaseUrl}/assets/svg/${filename}`;
    const fallbackUrl =
      type === 'fauna'
        ? `${apiBaseUrl}/assets/svg/lobo_marino${!isLightMode ? '_blanca' : ''}.svg`
        : '';

    let active = true;
    fetch(primaryUrl)
      .then((res) => {
        if (res.ok) return res.text();
        if (fallbackUrl) {
          return fetch(fallbackUrl).then((res2) => (res2.ok ? res2.text() : ''));
        }
        return '';
      })
      .then((text) => {
        if (active && text) {
          setDynamicSvg(text);
        }
      })
      .catch((err) => {
        console.warn(`Error loading dynamic ${type} SVG on mobile:`, err);
      });

    return () => {
      active = false;
    };
  }, [type, title, isLightMode]);

  const renderIcon = () => {
    if (markerSvg) {
      return (
        <View
          style={{
            width: size,
            height: size,
            alignItems: 'center',
            justifyContent: 'center',
          }}
        >
          {/* Base Shadow */}
          <Svg width={size} height={size} viewBox="0 0 64 64" style={StyleSheet.absoluteFill}>
            <Ellipse
              cx="32"
              cy="52"
              rx="20"
              ry="6"
              fill={isLightMode ? 'rgba(0,0,0,0.1)' : 'rgba(0,0,0,0.2)'}
            />
          </Svg>
          <SvgXml
            xml={markerSvg}
            width={size * 0.8}
            height={size * 0.8}
            color={isSelected ? '#3B82F6' : isLightMode ? '#2D3748' : '#FFFFFF'}
          />
        </View>
      );
    } else if (
      imageUrl &&
      imageUrl !==
        'https://images.unsplash.com/photo-1501281668745-f7f57925c3b4?auto=format&fit=crop&q=80&w=800'
    ) {
      return (
        <View
          style={{
            width: size,
            height: size,
            alignItems: 'center',
            justifyContent: 'center',
          }}
        >
          {/* Base Shadow */}
          <Svg width={size} height={size} viewBox="0 0 64 64" style={StyleSheet.absoluteFill}>
            <Ellipse
              cx="32"
              cy="52"
              rx="20"
              ry="6"
              fill={isLightMode ? 'rgba(0,0,0,0.1)' : 'rgba(0,0,0,0.2)'}
            />
          </Svg>
          <Image
            source={{ uri: imageUrl }}
            style={{ width: size * 0.8, height: size * 0.8, resizeMode: 'contain' }}
          />
        </View>
      );
    }

    switch (type) {
      case 'museo':
        return <MuseumIcon size={size} isLightMode={isLightMode} />;
      case 'coliseo':
        return <ColiseumIcon size={size} isLightMode={isLightMode} />;
      case 'puerto':
        return <PortIcon size={size} isLightMode={isLightMode} />;
      case 'teatro':
        return <TheaterIcon size={size} isLightMode={isLightMode} />;
      case 'parque':
        return <ParkIcon size={size} isLightMode={isLightMode} />;
      case 'hospital':
        return <HospitalIcon size={size} isLightMode={isLightMode} />;
      case 'universidad':
        if (dynamicSvg) {
          return (
            <View
              style={{
                width: size,
                height: size,
                alignItems: 'center',
                justifyContent: 'center',
              }}
            >
              {/* Base Shadow */}
              <Svg width={size} height={size} viewBox="0 0 64 64" style={StyleSheet.absoluteFill}>
                <Ellipse
                  cx="32"
                  cy="54"
                  rx="20"
                  ry="6"
                  fill={isLightMode ? 'rgba(0,0,0,0.1)' : 'rgba(0,0,0,0.2)'}
                />

                {/* Pin shape with white background */}
                <Path
                  d="M32 6 C21 6 12 15 12 26 C12 40 32 58 32 58 C32 58 52 40 52 26 C52 15 43 6 32 6 Z"
                  fill="#FFFFFF"
                  stroke="#CBD5E0"
                  strokeWidth="1.5"
                />
              </Svg>
              <View
                style={{
                  position: 'absolute',
                  top: size * 0.19,
                  left: size * 0.28,
                  width: size * 0.44,
                  height: size * 0.44,
                  alignItems: 'center',
                  justifyContent: 'center',
                }}
              >
                <SvgXml xml={dynamicSvg} width="100%" height="100%" />
              </View>
            </View>
          );
        }
        return <UniversityIcon size={size} isLightMode={isLightMode} />;
      case 'bombero':
        return <BomberoIcon size={size} isLightMode={isLightMode} />;
      case 'carabinero':
        return <CarabineroIcon size={size} isLightMode={isLightMode} />;
      case 'camara':
        return <CamaraIcon size={size} isLightMode={isLightMode} />;
      case 'fauna':
        if (dynamicSvg) {
          return (
            <View
              style={{
                width: size,
                height: size,
                alignItems: 'center',
                justifyContent: 'center',
              }}
            >
              {/* Base Shadow */}
              <Svg width={size} height={size} viewBox="0 0 64 64" style={StyleSheet.absoluteFill}>
                <Ellipse
                  cx="32"
                  cy="52"
                  rx="20"
                  ry="6"
                  fill={isLightMode ? 'rgba(0,0,0,0.1)' : 'rgba(0,0,0,0.2)'}
                />
              </Svg>
              <SvgXml
                xml={dynamicSvg}
                width={size * 0.8}
                height={size * 0.8}
                color={isSelected ? '#3B82F6' : isLightMode ? '#2D3748' : '#FFFFFF'}
              />
            </View>
          );
        }
        return <FaunaIcon size={size} isLightMode={isLightMode} />;
      case 'escultura':
        return <SculptureIcon size={size} isLightMode={isLightMode} />;
      case 'torreon':
        return <TowerIcon size={size} isLightMode={isLightMode} />;
      case 'estatua':
        return <StatueIcon size={size} isLightMode={isLightMode} />;
      case 'arte':
        return <ArtIcon size={size} isLightMode={isLightMode} />;
      default:
        return null;
    }
  };

  return <View style={[styles.container, isSelected && styles.selected]}>{renderIcon()}</View>;
};

const styles = StyleSheet.create({
  container: {
    alignItems: 'center',
    justifyContent: 'center',
    // Soft floating animation could be added here
  },
  selected: {
    transform: [{ scale: 1.2 }],
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 10 },
    shadowOpacity: 0.2,
    shadowRadius: 10,
  },
});
